class MinStack:
    def __init__(self):
        self.stack = []      # main stack
        self.min_stack = []  # auxiliary: tracks current min

    def push(self, val: int) -> None:
        self.stack.append(val)
        # Push current min to min_stack (or val if min_stack is empty)
        curr_min = min(val, self.min_stack[-1] if self.min_stack else val)
        self.min_stack.append(curr_min)

    def pop(self) -> None:
        self.stack.pop()
        self.min_stack.pop()   # always pop in sync

    def top(self) -> int:
        return self.stack[-1]

    def get_min(self) -> int:
        return self.min_stack[-1]  # O(1) — no scan

ms = MinStack()
for v in [5, 3, 7, 2, 8]:
    ms.push(v)
    print(f'pushed {v}, min={ms.get_min()}')
# 5→5, 3→3, 7→3, 2→2, 8→2

class MyQueue:
    def __init__(self):
        self.in_stack  = []   # for push
        self.out_stack = []   # for pop/peek

    def push(self, x: int) -> None:
        self.in_stack.append(x)   # always push to in_stack O(1)

    def _transfer(self):
        if not self.out_stack:    # lazy transfer — only when out is empty
            while self.in_stack:
                self.out_stack.append(self.in_stack.pop())

    def pop(self) -> int:
        self._transfer()
        return self.out_stack.pop()  # O(1) amortized

    def peek(self) -> int:
        self._transfer()
        return self.out_stack[-1]    # O(1) amortized

    def empty(self) -> bool:
        return not self.in_stack and not self.out_stack

# Amortized analysis:
# Each element: pushed once to in_stack, moved once to out_stack, popped once
# → 3 operations total → O(1) amortized per push/pop
